// Workers Builds runs `bun run build` + `npx wrangler deploy` from the repo root, but the
// deployable config is generated by the portal's Vite build (portal/build/server/wrangler.json).
// Wrangler only discovers generated configs via a .wrangler/deploy/config.json redirect in its
// cwd, so write one at the repo root pointing at the portal build output.
import { mkdirSync, writeFileSync, existsSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = resolve(dirname(fileURLToPath(import.meta.url)), '..');
const configPath = 'portal/build/server/wrangler.json';

if (!existsSync(join(root, configPath))) {
  console.error(`write-deploy-redirect: ${configPath} not found — run the portal build first`);
  process.exit(1);
}

const redirectDir = join(root, '.wrangler', 'deploy');
mkdirSync(redirectDir, { recursive: true });
writeFileSync(
  join(redirectDir, 'config.json'),
  // configPath is resolved relative to the redirect file's directory.
  JSON.stringify({ configPath: join('..', '..', configPath), auxiliaryWorkers: [] }, null, 2) + '\n'
);
console.log(`write-deploy-redirect: .wrangler/deploy/config.json -> ${configPath}`);
